use actix_web::{get, HttpRequest, HttpResponse};
use std::fs;
use std::path::PathBuf;

#[get("/uploads/{filename}")]
async fn serve_file(req: &HttpRequest) -> Result<HttpResponse, ()> {
    let filename = req.match_info().get("filename").unwrap();
    let path = PathBuf::from("uploads").join(filename);
    match fs::read(&path) {
        Ok(file_contents) => Ok(HttpResponse::Ok()
            .content_type(req.guess_mime_type())
            .body(file_contents)),
        Err(_) => Err(()),
    }
}